from datetime import datetime, timedelta


def next_fire(cron: str, after: datetime) -> datetime:
    fields = cron.split()
    if len(fields) != 5:
        raise ValueError("cron must have 5 fields")

    def parse(field, lo, hi):
        if field == "*":
            return None
        vals = set()
        for part in field.split(","):
            v = int(part)
            if v < lo or v > hi:
                raise ValueError("value out of range")
            vals.add(v)
        return vals

    minutes = parse(fields[0], 0, 59)
    hours = parse(fields[1], 0, 23)
    doms = parse(fields[2], 1, 31)
    months = parse(fields[3], 1, 12)
    dows = parse(fields[4], 0, 6)

    def day_matches(dt):
        # cron dow: 0=Sunday..6=Saturday; Python weekday(): 0=Monday..6=Sunday
        cron_dow = (dt.weekday() + 1) % 7
        if doms is not None and dows is not None:
            return dt.day in doms or cron_dow in dows
        if doms is not None:
            return dt.day in doms
        if dows is not None:
            return cron_dow in dows
        return True

    def advance_month(dt):
        if dt.month == 12:
            return dt.replace(year=dt.year + 1, month=1, day=1, hour=0, minute=0)
        return dt.replace(month=dt.month + 1, day=1, hour=0, minute=0)

    # start strictly after, truncated to minute granularity
    candidate = after.replace(second=0, microsecond=0) + timedelta(minutes=1)

    # bound the search to avoid infinite loops (8 years covers leap cycles)
    limit = candidate + timedelta(days=366 * 8)
    while candidate <= limit:
        if months is not None and candidate.month not in months:
            candidate = advance_month(candidate)
            continue
        if not day_matches(candidate):
            candidate = (candidate + timedelta(days=1)).replace(hour=0, minute=0)
            continue
        if hours is not None and candidate.hour not in hours:
            candidate = (candidate + timedelta(hours=1)).replace(minute=0)
            continue
        if minutes is not None and candidate.minute not in minutes:
            candidate = candidate + timedelta(minutes=1)
            continue
        return candidate
    raise ValueError("no matching time found")

